# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string

app = Flask(__name__)

@app.route('/')
def welcome():
    username = request.args.get('username', 'Guest')
    bio = request.args.get('bio', 'This user has not provided a bio yet.')
    location = request.args.get('location', 'Unknown')
    status_message = request.args.get('status_message', 'No Status Update Yet.')
    
    html = render_template_string("""
    <!DOCTYPE html>
    <html>
        <head>
            <title>Welcome Dashboard</title>
            <style>
                body {{ font-family: Arial, sans-serif; }}
                h1 {{ color: #333; text-align: center; padding: 50px; }}
                p {{ margin: auto; width: 70%; line-height: 2em; }}
            </style>
        </head>
        <body>
            <h1>Welcome, <b>{{ username }}</b></h1>
            <p><strong>Bio:</strong> <span style="white-space: pre-wrap;">{{ bio|safe }}</span></p>
            <p><strong>Location:</strong> {{ location }}</p>
            <p><strong>Status:</strong> <span style="white-space: pre-wrap;">{{ status_message|safe }}</span></p>
        </body>
    </html>
    """, username=username, bio=bio, location=location, status_message=status_message)
    
    return html

if __name__ == "__main__":
    app.run(port=5001)